import type { IntlShape } from 'react-intl';

import { XYCHART_MESSAGES } from '../../../messages/messages.js';
import type {
  XYAccessorDataTypes,
  XYChartData,
} from '../../../types/xy-chart.js';
import { isValidName } from '../../../utils/type-guards.js';
import { getDatumValue } from '../access-datapoint/get-datapoints.js';

export function getSeriesNameWithFallback(
  intl: IntlShape,
  seriesIndex: number,
  seriesNameFallback: XYAccessorDataTypes | undefined,
) {
  return isValidName(seriesNameFallback)
    ? String(seriesNameFallback)
    : intl.formatMessage(XYCHART_MESSAGES.unnamedSeriesMessage, {
        index: seriesIndex + 1,
      });
}

export function getSeriesNameWithAccessor(
  intl: IntlShape,
  seriesIndex: number,
  seriesNameFallback: string | undefined,
  seriesNameAccessor: string | undefined,
  datum: XYChartData,
) {
  const seriesNameFromAccessor = getDatumValue(datum, seriesNameAccessor);

  const finalSeriesName = seriesNameFromAccessor ?? seriesNameFallback;

  const seriesNameValidated = getSeriesNameWithFallback(
    intl,
    seriesIndex,
    finalSeriesName,
  );

  return seriesNameValidated;
}
